public:
    CombinationIterator(string characters, int combinationLength) {
        std::sort(characters.begin(), characters.end());
        std::generate_n(std::back_inserter(combinations), 
                         std::prev(std::upper_bound(std::begin(factorials), std::end(factorials), 
                                                    characters.size() / (double)combinationLength, 
                                                    [](int a, int b) {return a < b; } 
                                                   )), 
                         [characters, combinationLength](int i) {return std::vector<char>(characters.begin() + i, characters.begin() + i + combinationLength); });
        current = 0;
    }

    string next() {
        std::string result(combinations[current].begin(), combinations[current].end());
        ++current;
        return result;
    }

    bool hasNext() {
        return current < combinations.size();
    }
private:
    std::vector<std::vector<char>> combinations;
    int current;
};
