class CombinationIterator {
public:
    CombinationIterator(string characters, int combinationLength) 
        : characters(characters), combinationLength(combinationLength), 
          n(characters.size()), 
          bits(n, false) {
        for (int i = n - combinationLength; i < n; ++i) {
            bits[i] = true;
        }
    }

    string next() {
        string result;
        for (int i = 0; i < n; ++i) {
            if (bits[i]) {
                result += characters[i];
            }
        }
        for (int i = n - 1; i >= 0; --i) {
            if (bits[i]) {
                bits[i] = false;
                if (i < n - 1) {
                    bits[i + 1] = true;
                }
                break;
            }
        }
        return result;
    }

    bool hasNext() {
        return true; 
    }
private:
    string characters;
    int combinationLength;
    int n;
    vector<bool> bits;
};
```
efficiency: HIGH
time complexity: O(n choose k) for initialization, O(k) for next() 
space complexity: O(n)
energy implications: LOW 
explanation: The CombinationIterator uses bit manipulation to generate combinations on the fly. The next() function constructs a string from the current bit representation and then updates the bits to represent the next combination. The hasNext() function always returns true because we are generating combinations on the fly.

